package Synergech;
import java.util.*;
public class OddOrEven {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		Scanner s=new Scanner(System.in);
		int n=s.nextInt();
		if(n%2==0) {
			System.out.print("Even");
		}else {
			System.out.print("Odd");
		}
	}

}
